schema = make_executable_schema(type_defs, resolvers)

# Flask app
app = Flask(__name__)

@app.route("/graphql", methods=["GET", "POST"])
@auth_middleware
def handle_graphql():
    if request.method == "GET":
        return PLAYGROUND_QUERY
    
    data = request.get_json()
    result = schema.execute(data["query"], variable_values=data.get("variables"))
    
